python3 <<'PY'
import yaml, glob, sys, os
required_top = {
    "artifact.id", "artifact.prefix", "artifact.phase",
    "output.location", "output.naming",
    "id_format.prefix", "id_format.pattern", "id_format.example",
    "prompts.generation", "prompts.review",
    "template.file",
    "examples",
}
files = sorted(glob.glob("workflows/phases/*/artifacts/*/meta.yml"))
print("Total meta.yml files:", len(files))
for f in files:
    with open(f) as fh:
        try:
            data = yaml.safe_load(fh)
        except Exception as e:
            print(f"YAMLERR: {f}: {e}")
            continue
    missing = []
    def get(d, path):
        cur = d
        for k in path.split("."):
            if not isinstance(cur, dict): return None
            cur = cur.get(k)
        return cur
    for k in sorted(required_top):
        v = get(data, k)
        if v in (None, "", [], {}):
            missing.append(k)
    if missing:
        print(f"{f}: MISSING {missing}")
    else:
        print(f"{f}: OK")
PY
